#include <cuda_runtime.h>
#include <executorch/backends/aoti/slim/c10/core/DeviceType.h>
#include <executorch/backends/aoti/slim/c10/core/ScalarType.h>
#include <executorch/backends/cuda/runtime/shims/int4_plain_mm.h>
#include <executorch/backends/cuda/runtime/shims/memory.h>
#include <executorch/runtime/core/error.h>
#include <executorch/runtime/platform/platform.h>
#include <gtest/gtest.h>
#include <cmath>
#include <vector>

using executorch::backends::cuda::aoti_torch_cuda_int4_plain_mm;
using executorch::backends::cuda::aoti_torch_empty_strided;
using executorch::backends::cuda::AOTITorchError;
using executorch::runtime::Error;
namespace slim_c10 = executorch::backends::aoti::slim::c10;

using Tensor = executorch::backends::aoti::slim::SlimTensor;

class AOTITorchInt4PlainMMTest : public ::testing::Test {
 protected:
  void SetUp() override {
    et_pal_init();

    int device_count = 0;
    cudaError_t err = cudaGetDeviceCount(&device_count);
    if (err != cudaSuccess || device_count == 0) {
      GTEST_SKIP() << "CUDA not available";
    }
  }

  Tensor* create_tensor(
      const std::vector<int64_t>& sizes,
      slim_c10::ScalarType dtype) {
    Tensor* tensor;
    AOTITorchError error = aoti_torch_empty_strided(
        sizes.size(),
        sizes.data(),
        nullptr,
        static_cast<int32_t>(dtype),
        static_cast<int32_t>(slim_c10::DeviceType::CUDA),
        0,
        &tensor);
    return (error == Error::Ok) ? tensor : nullptr;
  }

  Tensor* create_bf16(const std::vector<int64_t>& sizes) {
    return create_tensor(sizes, slim_c10::ScalarType::BFloat16);
  }

  Tensor* create_uint8(const std::vector<int64_t>& sizes) {
    return create_tensor(sizes, slim_c10::ScalarType::Byte);
  }

  // Upload raw bytes to a CUDA tensor.
  void upload(Tensor* t, const void* host_data, size_t bytes) {
    cudaMemcpy(t->data_ptr(), host_data, bytes, cudaMemcpyHostToDevice);
  }

  // Download CUDA tensor to host buffer.
  void download(const Tensor* t, void* host_data, size_t bytes) {
    cudaMemcpy(host_data, t->data_ptr(), bytes, cudaMemcpyDeviceToHost);
  }

  // Run the shim and return the output tensor (asserts success).
  Tensor* run(
      Tensor* A,
      Tensor* qdata,
      Tensor* scale,
      Tensor* zero,
      int64_t group_size) {
    Tensor* output = nullptr;
    AOTITorchError error = aoti_torch_cuda_int4_plain_mm(
        A, qdata, scale, zero, group_size, &output);
    EXPECT_EQ(error, Error::Ok);
    EXPECT_NE(output, nullptr);
    return output;
  }

  // Check output bf16 values against expected, with absolute tolerance.
  void check_bf16_output(
      Tensor* output,
      const uint16_t* expected_data,
      int64_t count,
      float atol = 0.1f) {
    std::vector<uint16_t> actual(count);
    download(output, actual.data(), count * sizeof(uint16_t));
    cudaDeviceSynchronize();

    for (int64_t i = 0; i < count; i++) {
      // Convert bf16 raw bits to float: bf16 is the upper 16 bits of float32.
      uint32_t actual_bits = static_cast<uint32_t>(actual[i]) << 16;
      uint32_t expected_bits = static_cast<uint32_t>(expected_data[i]) << 16;
      float actual_f, expected_f;
      memcpy(&actual_f, &actual_bits, sizeof(float));
      memcpy(&expected_f, &expected_bits, sizeof(float));

      EXPECT_NEAR(actual_f, expected_f, atol)
          << "Mismatch at index " << i << ": actual=" << actual_f
          << " expected=" << expected_f;
    }
  }
};

// MultiGroupRandom: M=1, N=4, K=32, gs=16
// scale/zero layout: [K//gs=2, N=4]
TEST_F(AOTITorchInt4PlainMMTest, MultiGroupRandom) {
  int64_t M = 1, K = 32, N = 4, gs = 16;

  // clang-format off
  uint8_t qdata_host[] = {
      0x36, 0xEC, 0x7A, 0x4C, 0x96, 0x62, 0xAA, 0x47,
      0x73, 0x27, 0x45, 0x71, 0xDB, 0x15, 0xBF, 0x04,
      0x9B, 0xC5, 0x8B, 0xA0, 0xEA, 0xF9, 0xBB, 0xEF,
      0xDD, 0xDE, 0xB2, 0x36, 0x8F, 0x42, 0x62, 0x84,
      0x16, 0x83, 0xDB, 0x91, 0x98, 0x14, 0xB3, 0xBE,
      0xB6, 0x7C, 0x2E, 0x0D, 0x13, 0x37, 0xD1, 0x55,
      0x39, 0xC5, 0x1E, 0xB9, 0x91, 0x3D, 0xED, 0xEF,
      0xD7, 0xB6, 0xD8, 0x47, 0xCF, 0xE1, 0x74, 0x89
  };
  uint16_t scale_host[] = {0xBD86, 0x3DB0, 0xBE26, 0xBE0F, 0xBCC3, 0xBD4E, 0xBE7D, 0xBDBE};
  uint16_t zero_host[] = {0x4100, 0x4100, 0x4100, 0x4100, 0x4100, 0x4100, 0x4100, 0x4100};
  uint16_t A_host[] = {0x3FAD, 0xBF3D, 0x3F9E, 0x4002, 0x3F34, 0x3F9B, 0x3F49, 0x3F8F, 0x3FAD, 0x3DD8, 0x3DFA, 0xBFA5, 0xBF02, 0xBE45, 0x3F97, 0x3F5F, 0xBF85, 0x3DFD, 0x3EDE, 0x3E42, 0xBF86, 0xBE84, 0xBF06, 0x3F9E, 0xBF22, 0x3FDE, 0xBF2E, 0x3E6B, 0x3F72, 0xBEE5, 0x3EBB, 0xC00F};
  uint16_t expected[] = {0xBFCC, 0x3FB5, 0x4046, 0xC01E};
  // clang-format on

  Tensor* A = create_bf16({M, K});
  Tensor* qdata = create_uint8({N, K / 2});
  Tensor* scale = create_bf16({K / gs, N});
  Tensor* zero = create_bf16({K / gs, N});
  upload(A, A_host, sizeof(A_host));
  upload(qdata, qdata_host, sizeof(qdata_host));
  upload(scale, scale_host, sizeof(scale_host));
  upload(zero, zero_host, sizeof(zero_host));

  Tensor* output = run(A, qdata, scale, zero, gs);
  ASSERT_NE(output, nullptr);
  EXPECT_EQ(output->size(0), M);
  EXPECT_EQ(output->size(1), N);
  check_bf16_output(output, expected, M * N, 0.5f);
}

