TEST_F(AOTITorchInt4PlainMMTest, NullInputHandling) {
  int64_t M = 2, K = 128, N = 64, gs = 32;

  Tensor* A = create_bf16({M, K});
  Tensor* qdata = create_uint8({N, K / 2});
  Tensor* scale = create_bf16({K / gs, N});
  Tensor* zero = create_bf16({K / gs, N});
  Tensor* output = nullptr;

  EXPECT_EQ(
      aoti_torch_cuda_int4_plain_mm(nullptr, qdata, scale, zero, gs, &output),
      Error::InvalidArgument);
  EXPECT_EQ(
      aoti_torch_cuda_int4_plain_mm(A, nullptr, scale, zero, gs, &output),
      Error::InvalidArgument);
  EXPECT_EQ(
      aoti_torch_cuda_int4_plain_mm(A, qdata, nullptr, zero, gs, &output),
      Error::InvalidArgument);
  EXPECT_EQ(
      aoti_torch_cuda_int4_plain_mm(A, qdata, scale, nullptr, gs, &output),
      Error::InvalidArgument);
  EXPECT_EQ(
      aoti_torch_cuda_int4_plain_mm(A, qdata, scale, zero, gs, nullptr),
      Error::InvalidArgument);
}

